+it('should render Android external warning content', () => {
+    const { container, getByTestId } = render(
+        <InAppPurchaseModal onClose={() => {}} open={true} subscription={{ External: External.Android } as any} />
+    );
+
+    expect(container).toHaveTextContent('Manage your subscription on Google Play');
+    expect(container).toHaveTextContent('Google Play');
+    expect(container).toHaveTextContent('Payments & subscriptions');
+    const boldNavigationNoun = container.querySelector('span.text-bold');
