+    expect(boldNavigationNoun).toHaveTextContent('Payments & subscriptions');
+    expect(container).not.toHaveTextContent('Google Play store');
+    expect(getByTestId('InAppPurchaseModal/onClose')).toHaveTextContent('Got it');
