+    expect(container.querySelector('.prompt')).not.toBeInTheDocument();
+});
+
+it('should render iOS external warning content', () => {
+    const { container, getByTestId } = render(
+        <InAppPurchaseModal onClose={() => {}} open={true} subscription={{ External: External.iOS } as any} />
+    );
+
+    expect(container).toHaveTextContent('Manage your subscription on Apple App Store');
+    expect(container).toHaveTextContent('Apple App Store');
+    expect(container).toHaveTextContent('Subscriptions');
+    const boldNavigationNoun = container.querySelector('span.text-bold');
+    expect(boldNavigationNoun).toBeInTheDocument();
+    expect(boldNavigationNoun).toHaveTextContent('Subscriptions');
+    expect(getByTestId('InAppPurchaseModal/onClose')).toHaveTextContent('Got it');
+});
+
